def solve(self, n, initialPosition):
    def backtrack(r, cols, diagonals1, diagonals2):
        if r == n:
            return 1
        else:
            count = 0
            for c in range(n):
                if c not in cols and r + c not in diagonals1 and r - c not in diagonals2:
                    cols.add(c)
                    diagonals1.add(r + c)
                    diagonals2.add(r - c)
                    count += backtrack(r + 1, cols, diagonals1, diagonals2)
                    cols.remove(c)
                    diagonals1.remove(r + c)
                    diagonals2.remove(r - c)
        return count

    return backtrack(0, set(), set(), set())

