class Solution {
public:
std::vector<std::vector<std::string>> solve(int n, int initialPosition) {
    int count = 0;

    std::function<int(int, std::set<int>, std::set<int>, std::set<int>)> backtrack = 
        [this, &count, n](int r, std::set<int> cols, std::set<int> diagonals1, std::set<int> diagonals2) {
        if (r == n) return 1;
        else {
            int localCount = 0;
            for (int c = 0; c < n; ++c)
                if (cols.find(c) == cols.end() && diagonals1.find(r + c) == diagonals1.end() && diagonals2.find(r - c) == diagonals2.end())
                    localCount += backtrack(r + 1, cols, diagonals1, diagonals2);
            return localCount;
        }
        };

    return backtrack(0, {}, {}, {});
};
}
